INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  2,
  'Your Pattern Map',
  'Day 2 - Your Pattern Map',
  19,
  '[{"type":"intro","dayNumber":2,"dayTitle":"Your Pattern Map","goal":"Build the map of when, where, and why you use","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"What today is about","paragraphs":["You cannot change what you cannot see. Today you build your personal pattern map: the exact times, places, emotions, and situations when urges appear. This map is what your entire quit plan will be built around.","Most people have never mapped their habit this clearly. They just experience urges as random and overwhelming. They are not random. They are almost completely predictable. And predictable means manageable."],"highlight":"Most people have never mapped their habit this clearly. They just experience urges as random and overwhelming. They are not random. They are almost completely predictable. And predictable means manageable."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-2.mp3","durationSeconds":420},{"type":"lesson","title":"Common smoking triggers","paragraphs":["Morning with first chai or coffee","After every meal","During work breaks","Under stress or pressure","After arguments or conflict","When bored or waiting","Socially when others are smoking","Driving or commuting","At night before sleep"],"highlight":"At night before sleep"},{"type":"lesson","title":"Common drinking triggers","paragraphs":["End of workday: unwinding ritual","Social gatherings or celebrations","Weekends as a reward","Loneliness at home","Stress relief after a hard day","Peer pressure in friend groups","Watching sports or cricket matches","Feeling that one drink helps sleep","Argument or emotional pain"],"highlight":"Argument or emotional pain"},{"type":"action_step","stepNumber":1,"title":"Write down or mentally note your answers to these four questions:","instructions":["WHEN: What are the 3 times today when the urge was strongest? (morning, after lunch, 6 PM, before sleep)","WHERE: What places are linked to the urge for you? (balcony, car, specific room, certain café)","WHAT EMOTION: What feeling was present just before the strongest urge today? (stressed, bored, lonely, celebratory, relieved)","WHAT HAPPENED JUST BEFORE: What action or situation triggered it? (finishing food, getting a difficult call, sitting alone)","You are not expected to resist any urge today: just observe and note it","The chai-cigarette pairing is one of the strongest habit links in India: if this applies to you, note it specifically","The more honest and specific your map, the more effective your quit plan will be"],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"What are my top 3 urge triggers? When, where, and what emotion?","helperText":"This is the most important reflection of the week. Be specific."},{"type":"close","message":"Day 2 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
