INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  3,
  'The Emotions Underneath',
  'Day 3 - The Emotions Underneath',
  19,
  '[{"type":"intro","dayNumber":3,"dayTitle":"The Emotions Underneath","goal":"Understand what the habit is really doing for you emotionally","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"What today is about","paragraphs":["Most people do not smoke or drink because they enjoy it. They smoke or drink because it changes how they feel. Stress becomes manageable. Boredom becomes bearable. Loneliness gets quieter. Social anxiety fades.","The substance is not the problem. The substance is the solution to an emotional problem. This is why willpower alone fails: you cannot remove a solution without replacing it with something that does the same job.","Today you identify exactly what emotional job your habit is doing. Because Phase 2 will give you better tools that do the same job: without the cost."],"highlight":"Today you identify exactly what emotional job your habit is doing. Because Phase 2 will give you better tools that do the same job: without the cost."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-3.mp3","durationSeconds":420},{"type":"lesson","title":"The 6 emotional jobs habits do","paragraphs":["Stress relief: the habit reduces cortisol and produces a brief calm","Boredom management: the habit fills empty time and gives the hands something to do","Loneliness reduction: the habit is a companion when human connection is absent","Reward signalling: the habit marks the end of effort and signals that rest is deserved","Social belonging: the habit creates a shared ritual that connects you to others","Emotional numbing: the habit dulls pain, grief, anxiety or anger that feels too large"],"highlight":"Emotional numbing: the habit dulls pain, grief, anxiety or anger that feels too large"},{"type":"action_step","stepNumber":1,"title":"Today''s practice: Name the job","instructions":["Think about your strongest urge from yesterday. Which of these 6 emotional jobs was the habit doing in that moment?","Now think about your three most common urge triggers from Day 2. Is the same emotional job appearing each time? Or are different jobs running in different situations?","This is not about judging the emotion. Stress is real. Loneliness is real. The need to reward yourself is real.","Understanding which emotional need the habit is meeting tells you exactly what coping tools you need to build in Phase 2."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"Which emotional job does my habit do most often? What is it actually giving me?","helperText":"Be honest. There is no wrong answer. This is the insight that makes Phase 2 work."},{"type":"close","message":"Day 3 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
