INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  4,
  'The Cost of Continuing',
  'Day 4 - The Cost of Continuing',
  19,
  '[{"type":"intro","dayNumber":4,"dayTitle":"The Cost of Continuing","goal":"Make the real cost visible: not to shame, but to motivate","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"What today is about","paragraphs":["Most people underestimate their consumption and underestimate the cost. Not because they are dishonest: because the brain protects them from it. Today brings it into the light. Not to create shame: to create honest motivation.","Shame has never made anyone quit permanently. Honest, clear, personal motivation does. Today you calculate exactly what continuing costs you."],"highlight":"Shame has never made anyone quit permanently. Honest, clear, personal motivation does. Today you calculate exactly what continuing costs you."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-4.mp3","durationSeconds":420},{"type":"lesson","title":"The financial cost","paragraphs":["Average smoker in India: 10 cigarettes daily at ₹15 each = ₹150 per day","₹150 per day = ₹4,500 per month = ₹54,000 per year","5 years = ₹2,70,000. 10 years = ₹5,40,000","Calculate your own: daily spend × 365 × years you plan to quit by","Write the actual number. See it clearly."],"highlight":"Write the actual number. See it clearly."},{"type":"lesson","title":"The health cost: smoking","paragraphs":["Every cigarette reduces life expectancy by approximately 11 minutes","Smokers have a 2 to 3 times higher risk of heart attack","Risk of lung cancer is 15 to 30 times higher than non-smokers","Circulation problems, erectile dysfunction, skin ageing, tooth loss","The body starts recovering within 20 minutes of the last cigarette"],"highlight":"The body starts recovering within 20 minutes of the last cigarette"},{"type":"lesson","title":"The health cost: alcohol","paragraphs":["Regular heavy drinking damages the liver, heart, and brain","Significantly increases risk of 7 types of cancer","Disrupts sleep architecture: alcohol prevents deep REM sleep","Increases anxiety and depression over time despite temporary relief"],"highlight":"Increases anxiety and depression over time despite temporary relief"},{"type":"lesson","title":"The hidden costs","paragraphs":["Relationships: the habit creates distance even when subtle","Self-respect: the gap between who you want to be and who you are","Energy: the fatigue, the brain fog, the morning regret","Freedom: always planning around the next one","Time: the hours accumulated over years","Affects testosterone, sexual health, and cognitive sharpness"],"highlight":"Affects testosterone, sexual health, and cognitive sharpness"},{"type":"action_step","stepNumber":1,"title":"Today''s practice: Your personal calculation","instructions":["Calculate your real monthly and yearly cost: financial, health, and personal. Write the actual numbers. Make it specific to you."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":2,"title":"Then write this sentence:","instructions":["\"Continuing to smoke/drink costs me ₹_____ every year. Quitting gives me that back.\""],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"What is the real cost: financial, health, relationships, self-respect: of continuing for another year? Write the actual numbers. This is not about guilt. It is about seeing clearly.","helperText":"A short honest reflection is enough."},{"type":"close","message":"Day 4 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
