INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  5,
  'What the Body Goes Through',
  'Day 5 - What the Body Goes Through',
  19,
  '[{"type":"intro","dayNumber":5,"dayTitle":"What the Body Goes Through","goal":"Know what withdrawal feels like so you are not afraid of it","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"What today is about","paragraphs":["Most quit attempts fail in the first 72 hours: not because the person is weak but because withdrawal symptoms feel alarming when you do not know what they are. Panic makes withdrawal worse. Knowledge makes it manageable. Today you read exactly what to expect. When you know what is coming, it loses its power to frighten you."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-5.mp3","durationSeconds":420},{"type":"lesson","title":"Nicotine withdrawal: what to expect","paragraphs":["Hours 1–4: Irritability, restlessness, difficulty concentrating. This is the brain asking for its chemical.","Hours 4–24: Peak cravings, headache, mild anxiety, increased appetite. Normal and temporary.","Days 2–3: The hardest 48 hours. Mood dips, strong cravings, disturbed sleep. This is the peak.","Days 4–7: Cravings reduce in frequency. Energy starts returning. Sleep improves.","Week 2 onwards: Most physical symptoms gone. What remains is mostly habit and emotion.","Important: A craving peaks at 3 to 5 minutes and then drops: whether you act on it or not."],"highlight":"Important: A craving peaks at 3 to 5 minutes and then drops: whether you act on it or not."},{"type":"lesson","title":"Alcohol reduction: what to expect","paragraphs":["Hours 6–12: Mild anxiety, shakiness, headache if reducing from heavy use.","Hours 12–48: For heavy drinkers: sweating, tremors, difficulty sleeping. See a doctor if severe.","Days 2–4: Sleep disruption, irritability, strong cravings in the evening.","Days 5–7: Physical symptoms largely pass. Brain fog begins lifting.","Week 2: Energy improving, sleep deepening, appetite stabilising.","WARNING: If you experience severe tremors, confusion, or seizures: emergency care immediately."],"highlight":"WARNING: If you experience severe tremors, confusion, or seizures: emergency care immediately."},{"type":"lesson","title":"The body starts healing immediately","paragraphs":["20 minutes after last cigarette: heart rate and blood pressure drop to normal levels","8 hours after: carbon monoxide levels in blood drop by half. Oxygen levels normalise.","24 hours after: risk of heart attack begins decreasing","48 hours after: nerve endings start regrowing. Taste and smell begin returning.","2 weeks after: circulation improves. Lung function begins increasing.","24 hours after stopping alcohol: liver begins processing stored fat again","1 week without alcohol: sleep quality improves significantly. Brain chemistry begins rebalancing.","1 month without alcohol: liver inflammation reduces. Skin clears. Energy returns.","Heavy alcohol users: do not stop abruptly without medical guidance. Withdrawal seizures are a real risk. Call 1800-11-2356 or see a doctor first.","These physical symptoms are temporary. They are the body healing, not the body failing."],"highlight":"These physical symptoms are temporary. They are the body healing, not the body failing."},{"type":"journal","prompt":"Which withdrawal symptom am I most worried about? Now that I know what to expect, how does that feel?","helperText":"Knowledge reduces fear. Write what you now understand."},{"type":"close","message":"Day 5 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
