INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  9,
  'Urge Surfing',
  'Day 9 - Urge Surfing',
  19,
  '[{"type":"intro","dayNumber":9,"dayTitle":"Urge Surfing","goal":"Ride the urge like a wave instead of fighting it or giving in","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["Urge Surfing was developed by Dr. Alan Marlatt at the University of Washington and is now used in addiction treatment programmes worldwide. It is different from the Delay Technique: instead of distracting from the urge, you pay full attention to it. You watch it rise. You watch it peak. You watch it fall.","This sounds counterintuitive. It works because fighting urges gives them power. Watching them without reacting shows the brain they are not dangerous: and not dangerous things stop producing urges."],"highlight":"This sounds counterintuitive. It works because fighting urges gives them power. Watching them without reacting shows the brain they are not dangerous: and not dangerous things stop producing urges."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-9.mp3","durationSeconds":420},{"type":"lesson","title":"Urge Surfing: how to do it","paragraphs":["When the urge appears: sit down if possible. Do not try to distract yourself. Turn your full attention TO the urge.","Notice it as a physical sensation in your body. Where do you feel it? Chest? Throat? Hands? Mouth? Describe it to yourself: tight, burning, restless, pressured.","Watch it rise. The urge will get stronger for 1 to 3 minutes. Stay with it. Say to yourself: \"This is the wave rising. It will peak and fall.\"","Watch it peak. This is the highest point. Notice: you are still here. The urge has not hurt you. You are simply observing a physical sensation.","Watch it fall. The urge drops: always within 5 to 20 minutes. Notice the fall. This is the most important moment. Your brain is learning.","After: notice that you rode the wave. You did not fight it. You did not give in. You simply observed it until it passed. Do this for every urge today."],"highlight":"After: notice that you rode the wave. You did not fight it. You did not give in. You simply observed it until it passed. Do this for every urge today."},{"type":"lesson","title":"Why this works better than willpower","paragraphs":["Willpower suppresses urges: which makes the brain more anxious and the urge stronger next time.","Urge Surfing exposes the brain to the urge without consequence: this is called extinction learning.","After repeated urge surfing, the urge-producing neural pathway weakens because it no longer receives a reward. The urges become shorter and less intense over 7 to 14 days.","Clinical trials show Urge Surfing reduces relapse rates by 22% compared to willpower-only approaches."],"highlight":"Clinical trials show Urge Surfing reduces relapse rates by 22% compared to willpower-only approaches."},{"type":"journal","prompt":"What did the urge feel like as a physical sensation? Where in your body? What happened when you watched it instead of fighting it?","helperText":"This reflection builds the skill. Write it even if the session was imperfect."},{"type":"action_step","stepNumber":1,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":2,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this.","Watched the urge rise and fall without acting: done, even partially"],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 9 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
