INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  10,
  'The Hardest Moments',
  'Day 10 - The Hardest Moments',
  19,
  '[{"type":"intro","dayNumber":10,"dayTitle":"The Hardest Moments","goal":"Specific plans for morning, after meals, and high-stress moments","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["Three moments are responsible for more than 60% of all relapses: the morning urge, the post-meal urge, and the stress-triggered urge. Today you build a specific, rehearsed plan for each one. Not a vague intention: an exact sequence of actions."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-10.mp3","durationSeconds":420},{"type":"action_step","stepNumber":1,"title":"The morning plan","instructions":["The morning cigarette or morning drink is the most addictive because cortisol peaks naturally on waking: and the brain has learned to couple this cortisol peak with the substance. The urge is strongest here."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":2,"title":"Exact morning replacement sequence:","instructions":["On waking: drink 500 ml of cold water immediately. This is the single most effective physiological urge-reducer available.","Move your body for 2 minutes: walk to another room, stretch, do 10 jumping jacks. Movement metabolises cortisol and reduces craving intensity.","If you drink chai: make the chai. Drink it. Then do something different for 3 minutes before the cigarette urge peaks. Break the automatic chai-cigarette sequence.","Put saunf (fennel seeds) next to your chai cup. The mouth needs something after the chai. Give it something harmless."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":3,"title":"The post-meal plan","instructions":["The post-meal urge is a conditioned reflex: the brain has paired eating with smoking or drinking for years. The association is strong but it can be broken in 3 to 4 weeks by consistently interrupting the chain."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":4,"title":"Exact post-meal replacement:","instructions":["Immediately after finishing food: drink a glass of water. This resets the mouth signal.","Stand up and walk for 2 to 5 minutes. Change location. If you usually smoke on the balcony or terrace: go somewhere else first.","Chew something: saunf, elaichi (cardamom), or paan without tobacco. The chewing reflex satisfies the oral habit component."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":5,"title":"The stress plan","instructions":["Stress is the most common relapse trigger because the habit genuinely works: nicotine and alcohol do reduce cortisol temporarily. The replacement must also genuinely reduce stress, not just occupy time."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"The 3-breath stress reset:","paragraphs":["When stress peaks: inhale for 4 counts, hold for 1, exhale for 6 counts. Repeat 3 times. The long exhale activates the parasympathetic nervous system and drops cortisol within 90 seconds. This is the same mechanism as the cigarette: without the nicotine."]},{"type":"journal","prompt":"Which of these three moments was hardest today? Did the replacement plan help? What would make it better? One sentence is enough. Or skip entirely.","helperText":"A short honest reflection is enough."},{"type":"action_step","stepNumber":6,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done. Do this in the next 60 minutes:","Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 10 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
