INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  13,
  'Your Body is Healing',
  'Day 13 - Your Body is Healing',
  19,
  '[{"type":"intro","dayNumber":13,"dayTitle":"Your Body is Healing","goal":"See the physical recovery that is already happening inside you","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["By Day 13 of reduced or eliminated use, significant physical healing is already underway. Most of it is invisible. Today you make it visible: because knowing your body is healing gives you a powerful reason to protect what you have already rebuilt."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-13.mp3","durationSeconds":420},{"type":"lesson","title":"What has already happened: smoking","paragraphs":["Within 20 minutes of your last cigarette: heart rate normalised","Within 8 hours: carbon monoxide in blood dropped by half","Within 24 hours: risk of heart attack began decreasing","Within 48 hours: nerve endings began regrowing: taste and smell improving","By Day 3: nicotine is physically out of your blood entirely","By Day 7: lung cilia (cleaning hairs) have begun regrowing and moving mucus out","By Day 13: circulation measurably improved. Breathing slightly easier."],"highlight":"By Day 13: circulation measurably improved. Breathing slightly easier."},{"type":"lesson","title":"What has already happened: alcohol","paragraphs":["Within 24 hours: liver began processing fat again","Within 48 hours: blood sugar stabilising without alcohol-induced spikes and crashes","By Day 5: most physical withdrawal symptoms past for moderate users","By Day 7: sleep quality measurably deeper. REM sleep returning.","By Day 10: brain chemistry beginning to rebalance dopamine production","By Day 13: skin hydration measurably improved","By Day 14: liver inflammation significantly reduced","By Week 3: mental clarity, energy, and mood all measurably improved","By Day 14: lung function has increased. Stamina beginning to return."],"highlight":"By Day 14: lung function has increased. Stamina beginning to return."},{"type":"lesson","title":"The brain is changing","paragraphs":["Nicotine and alcohol both suppress the brain''s natural dopamine production. Without the substance, dopamine levels initially drop: causing the low mood and irritability of withdrawal.","By Day 10 to 14, the brain begins upregulating its own dopamine receptors. Natural pleasures start feeling more rewarding again.","This rebalancing is what former users mean when they say \"I feel more like myself.\" It is not metaphorical. It is neurological."],"highlight":"This rebalancing is what former users mean when they say \"I feel more like myself.\" It is not metaphorical. It is neurological."},{"type":"lesson","title":"What you may be noticing by now","paragraphs":["Food tastes sharper and better: taste buds regenerating","Breathing slightly easier when walking or climbing stairs","Waking up with clearer head: not the foggy morning start","Fewer urges than Day 3: they are still coming but shorter and less intense","Small amounts of pride that feel unfamiliar: that is self-respect returning"],"highlight":"Small amounts of pride that feel unfamiliar: that is self-respect returning"},{"type":"journal","prompt":"What physical change have I noticed in the last 13 days? What does it feel like to know my body is healing? One sentence is enough. Or skip entirely.","helperText":"A short honest reflection is enough."},{"type":"action_step","stepNumber":1,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done. Do this in the next 60 minutes:","Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 13 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
