INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  14,
  'Renew the Decision',
  'Day 14 - Renew the Decision',
  19,
  '[{"type":"intro","dayNumber":14,"dayTitle":"Renew the Decision","goal":"Return to your Day 7 decision and strengthen it with what you now know","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["Two weeks in. Today you return to the decision you wrote on Day 7. Not to judge how well you have done: to see how much you have learned. The decision is the same. The person making it is stronger."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-14.mp3","durationSeconds":420},{"type":"lesson","title":"Complete these honestly:","paragraphs":["The hardest moment of the last 7 days was:","The tool that helped most was:","Something that surprised me about quitting:","The biggest change I notice in myself:","What I want to protect most in the next 7 days:"],"highlight":"What I want to protect most in the next 7 days:"},{"type":"action_step","stepNumber":1,"title":"Return to The Decision","instructions":["Read the decision you wrote on Day 7.","Now rewrite it: not because the first one was wrong, but because you know more now. You know what the hardest moments feel like. You know which tools work for you. You know what the body has already healed."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":2,"title":"Write the renewed decision with this knowledge added:","instructions":["\"I am continuing this quit because _____. I know the hardest moments for me personally are _____. When those moments come, I will use _____. I am protecting _____.\"","Phase 3 begins tomorrow: it is about holding what you have built and building the permanent identity","The first 14 days are statistically the hardest. You have passed them.","If you have had slips this week: that is information, not failure. Phase 3 addresses this directly.","Most physical withdrawal is now largely complete. What remains is habit and emotional: the tools you now have."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"What is my renewed decision after the first 14 days?","helperText":"My renewed decision: written in full with what I now know after 14 days."},{"type":"lesson","title":"Phase 3 begins tomorrow","paragraphs":["Phase 3 is about permanence. The physical withdrawal is largely past. The tools are built. Now comes the work of making the quit last: the identity shift, the replacement rituals, the support network, and the honest preparation for the weeks and months ahead.","Weeks 3 to 12 are when most relapses happen: not because the habit returns but because vigilance drops. Phase 3 prepares you for this.","The most powerful protection is identity: \"I am not a smoker\" is stronger than \"I am trying to quit\".","Phase 3 ends on Day 21. The quit continues. The program gives you the tools. You carry them forward."],"highlight":"Phase 3 ends on Day 21. The quit continues. The program gives you the tools. You carry them forward."},{"type":"close","message":"Day 14 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
