INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  15,
  'Replacing the Ritual',
  'Day 15 - Replacing the Ritual',
  19,
  '[{"type":"intro","dayNumber":15,"dayTitle":"Replacing the Ritual","goal":"Build the replacement rituals that fill the space quitting leaves","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["Smoking and drinking are not just chemical habits. They are rituals. The morning routine. The after-work unwind. The social lubricant. The end-of-day marker. The thing that belongs to only you.","Quitting only the substance without replacing the ritual leaves a gap: and the substance rushes back to fill it. Today you build the replacement ritual that is genuinely yours."],"highlight":"Quitting only the substance without replacing the ritual leaves a gap: and the substance rushes back to fill it. Today you build the replacement ritual that is genuinely yours."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-15.mp3","durationSeconds":420},{"type":"lesson","title":"Every ritual has four components:","paragraphs":["A CUE: the time, place, or emotion that starts it","A PAUSE: stepping away from what you were doing","A PHYSICAL SENSATION: something the body does and feels","A CLOSE: a signal that the ritual is complete and you can return","The replacement ritual must hit all four points. A drink of water alone does not work as a ritual. But a walk to the water cooler, a glass of water drunk slowly, and 2 minutes outside before returning: that is a ritual."],"highlight":"The replacement ritual must hit all four points. A drink of water alone does not work as a ritual. But a walk to the water cooler, a glass of water drunk slowly, and 2 minutes outside before returning: that is a ritual."},{"type":"action_step","stepNumber":1,"title":"Replacement ritual options: smoking","instructions":["The 3-minute walk: same break, no cigarette. Different destination.","The chai ritual preserved: keep the chai, add saunf or cardamom after. Remove the cigarette.","The breathing ritual: 5 deep breaths outside. Physical sensation, clear close.","Cold water + 2 minutes outside: addresses the physical and the break need simultaneously","The phone call ritual: call someone for 3 minutes instead of smoking during the break"],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":2,"title":"Replacement ritual options: alcohol","instructions":["The evening unwind ritual: warm shower + 10 minutes reading or walking instead of the first drink","Lime soda with ice in a glass: same physical sensation, same social signal, zero alcohol","Chamomile tea after 8 PM: genuine calming effect, no rebound anxiety","Evening walk: 15 minutes outside after dinner: addresses the stress and transition need","The reward ritual: plan one genuinely enjoyable non-alcohol activity per evening this week"],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":3,"title":"Today''s practice: Build your ritual","instructions":["Choose one replacement ritual for your hardest trigger moment. Make it specific: what is the cue, what is the action, what closes it.","Use this ritual consistently for 7 days. Rituals require repetition to become automatic."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"What is my replacement ritual? Describe it specifically: the cue, the action, the close.","helperText":"One sentence is enough. Or skip entirely."},{"type":"action_step","stepNumber":4,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":5,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 15 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
