INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  18,
  'What Quitting Gives Back',
  'Day 18 - What Quitting Gives Back',
  19,
  '[{"type":"intro","dayNumber":18,"dayTitle":"What Quitting Gives Back","goal":"Make the gains from quitting concrete, specific, and yours","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["Quit programs spend a lot of time on what you are giving up. Today is entirely about what you are getting back. Making the gains specific, personal, and financially real is one of the strongest motivators for staying quit."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-18.mp3","durationSeconds":420},{"type":"lesson","title":"The financial recovery","paragraphs":["Calculate: what is your monthly saving from quitting?","Month 1 saving: ₹_____","Year 1 saving: ₹_____","5-year saving: ₹_____","Decide: what will you do with this money? A specific answer makes it more motivating than a general one.","Example: \"In 6 months I will have ₹27,000: enough for a trip to Goa.\""],"highlight":"Example: \"In 6 months I will have ₹27,000: enough for a trip to Goa.\""},{"type":"lesson","title":"The health recovery timeline","paragraphs":["1 month without smoking: lung function up by 30%","3 months: circulation fully restored, stamina markedly better","1 year without smoking: heart attack risk halved","10 years: lung cancer risk same as non-smoker","1 month without alcohol: liver inflammation gone, skin cleared, sleep deep","3 months without alcohol: brain chemistry fully rebalanced, mental clarity, emotional stability, genuine energy"],"highlight":"3 months without alcohol: brain chemistry fully rebalanced, mental clarity, emotional stability, genuine energy"},{"type":"lesson","title":"The hidden gains: what money cannot measure","paragraphs":["Freedom: not planning the day around the next cigarette or drink","Self-respect: the gap between who you wanted to be and who you are is closing","Presence: more available to the people and moments that matter","Energy: the genuine kind: not the artificial stimulation followed by the crash","The morning: waking without regret, without the cough, without the first thought being the habit","Pride: quiet, earned, growing"],"highlight":"Pride: quiet, earned, growing"},{"type":"journal","prompt":"What specific thing am I most looking forward to having back? In money, health, relationships, or self-respect?","helperText":"Be specific. The more personal and concrete, the more motivating."},{"type":"action_step","stepNumber":1,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":2,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 18 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
