INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  19,
  'Building Your Support System',
  'Day 19 - Building Your Support System',
  19,
  '[{"type":"intro","dayNumber":19,"dayTitle":"Building Your Support System","goal":"The one thing that triples long-term quit success rates","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["Research is unambiguous: people who have at least one person who knows they are quitting and actively supports them are 3 times more likely to stay quit at one year compared to people who quit alone.","Today you build your support system. Even one person is enough to significantly change your long-term outcomes."],"highlight":"Today you build your support system. Even one person is enough to significantly change your long-term outcomes."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-19.mp3","durationSeconds":420},{"type":"action_step","stepNumber":1,"title":"LAYER 1: Your personal supporter","instructions":["One person who knows you are quitting and will pick up the phone when you call. Not someone who will lecture you. Someone who will say \"I''ve got you, stay strong\" when you need it. This person does not need to understand addiction. They just need to be available.","Who is this person for you? Name them now. Tell them today if you have not already."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":2,"title":"LAYER 2: Professional support","instructions":["Indian Quitline: 1800-11-2356: Free, confidential, staffed by trained counsellors. Call when the urge is strong and no one is available. They have heard it all. There is no judgment.","iCall: 9152987821: If the quit is triggering anxiety, depression, or emotional difficulty.","KIRAN Mental Health: 1800-599-0019: 24/7, free, Hindi and English."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"LAYER 3: The app","paragraphs":["The app is your emergency fallback when no person is available. Open the current day, return to the tool you need, and follow the steps before acting on the urge."]},{"type":"action_step","stepNumber":3,"title":"What to tell your supporter","instructions":["You do not need a long conversation. Say this:","\"I am quitting smoking/drinking and I wanted you to know. I might need to call you when it is hard. I do not need advice: I just need you to pick up.\""],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"Who is my supporter and have I told them? How does it feel to not do this alone?","helperText":"One sentence is enough. Or skip entirely."},{"type":"action_step","stepNumber":4,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":5,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this.","Told them I am quitting: done, or made a plan to tell them today"],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 19 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
