INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  20,
  'The Long Game',
  'Day 20 - The Long Game',
  19,
  '[{"type":"intro","dayNumber":20,"dayTitle":"The Long Game","goal":"Prepare for the weeks and months after Day 21","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["Day 21 is tomorrow. The program ends. The quit continues.","Most relapses do not happen in the first three weeks: they happen in weeks 4 to 12, when the program structure is gone and vigilance drops. Today you build a specific plan for that period."],"highlight":"Most relapses do not happen in the first three weeks: they happen in weeks 4 to 12, when the program structure is gone and vigilance drops. Today you build a specific plan for that period."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-20.mp3","durationSeconds":420},{"type":"lesson","title":"What to expect after Day 21","paragraphs":["Week 4: Cravings are shorter and less frequent but will still appear. The brain is not fully rewired yet. This is normal. The tools still work: continue using them.","Weeks 5 to 8: The habit memory begins fading. Cravings become occasional rather than daily. This is when many people mistakenly believe \"I have this completely under control\" and drop the replacement rituals. Do not drop them yet.","Weeks 8 to 12: The statistical high-risk relapse window. Not because the habit is coming back: because life stress increases, the vigilance from the quit program is long gone, and one moment of weakness feels like it has no consequence."],"highlight":"Weeks 8 to 12: The statistical high-risk relapse window. Not because the habit is coming back: because life stress increases, the vigilance from the quit program is long gone, and one moment of weakness feels like it has no consequence."},{"type":"action_step","stepNumber":1,"title":"Write specific answers to these five questions:","instructions":["Which 3 tools will I keep using daily after Day 21?","What will I do if a strong craving appears in week 6 with no program to open?","Which situations in the next 3 months could be high-risk for me? (Family gathering, high stress period, celebration)","What is my plan for each high-risk situation?","Who will I call if I am close to relapsing at week 10?","Keep the Delay Technique and Urge Surfing as permanent tools: they work forever, not just for 21 days","Keep the replacement rituals going for at least 90 days. Habit memory fades slowly.","Check in with your supporter every week for at least 2 months after Day 21","If you slip in week 6 or 8: use the Day 12 slip recovery protocol. Nothing changes.","Coming back to this program on a hard day is not weakness. It is smart."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"My post-program plan: which tools do I keep, what are my high-risk situations, and what is my response plan?","helperText":"Be as specific as possible. Vague plans fail under pressure."},{"type":"close","message":"Day 20 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
